namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly Lock _lock = new();

    private readonly string[] _templates =
    [
        "New comment on your pull request",
        "Build succeeded for branch main",
        "Deployment to staging completed",
        "Security alert: dependency update available",
        "Your issue was closed",
        "New team member joined the project",
        "Code review requested",
        "Pipeline failed — check logs",
        "Release v{0} published",
        "Scheduled maintenance in 30 minutes"
    ];

    public Task<List<Notification>> GetInitialNotificationsAsync()
    {
        lock (_lock)
        {
            var notifications = Enumerable.Range(0, 3)
                .Select(_ => CreateNotification(DateTime.UtcNow.AddMinutes(-Random.Shared.Next(1, 60))))
                .OrderByDescending(n => n.Timestamp)
                .ToList();
            return Task.FromResult(notifications);
        }
    }

    public Task<List<Notification>> CheckForNewNotificationsAsync()
    {
        lock (_lock)
        {
            // ~40% chance of a new notification each poll
            if (Random.Shared.Next(100) < 40)
            {
                return Task.FromResult(new List<Notification> { CreateNotification(DateTime.UtcNow) });
            }
            return Task.FromResult(new List<Notification>());
        }
    }

    private Notification CreateNotification(DateTime timestamp)
    {
        var template = _templates[Random.Shared.Next(_templates.Length)];
        var message = template.Contains("{0}")
            ? string.Format(template, $"{Random.Shared.Next(1, 10)}.{Random.Shared.Next(0, 20)}")
            : template;
        return new Notification(_nextId++, message, timestamp);
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@using NotificationsApp.Services
@inject NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>
                    <strong>@n.Message</strong>
                </div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<Notification>? RestoredNotifications { get; set; }

    private List<Notification> notifications = new();
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        if (RestoredNotifications is not null)
        {
            // Interactive render: state was restored from prerender — skip refetch
            notifications = RestoredNotifications;
        }
        else
        {
            // Prerender (or first load without persisted state): fetch initial data
            notifications = await NotificationService.GetInitialNotificationsAsync();
            RestoredNotifications = notifications;
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                var newItems = await NotificationService.CheckForNewNotificationsAsync();
                if (newItems.Count > 0)
                {
                    notifications.InsertRange(0, newItems);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

