                return Task.FromResult(new List<Notification> { CreateNotification(DateTime.UtcNow) });
            }
            return Task.FromResult(new List<Notification>());
        }
    }

    private Notification CreateNotification(DateTime timestamp)
    {
        var template = _templates[Random.Shared.Next(_templates.Length)];
        var message = template.Contains("{0}")
            ? string.Format(template, $"{Random.Shared.Next(1, 10)}.{Random.Shared.Next(0, 20)}")
            : template;
        return new Notification(_nextId++, message, timestamp);
    }
